import{_ as o,o as t,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"75. Professional Development Leave","description":"","frontmatter":{"title":"75. Professional Development Leave","eba":"Nurses and Midwives 2024-2028","topics":["leave","education-pd","staffing"]},"headers":[],"relativePath":"ebas/nurses-midwives/education-pd/75-professional-development-leave.md","filePath":"ebas/nurses-midwives/education-pd/75-professional-development-leave.md"}'),s={name:"ebas/nurses-midwives/education-pd/75-professional-development-leave.md"};function r(i,e,l,p,d,m){return t(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_75-professional-development-leave" tabindex="-1">75. Professional Development Leave <a class="header-anchor" href="#_75-professional-development-leave" aria-label="Permalink to &quot;75. Professional Development Leave&quot;">​</a></h1><p>Other than clause 75.8, this clause does not apply to casual Employees.</p><p><strong>75.1</strong> Professional Development Leave</p><p><strong>(a)</strong> All Nurses and Midwives must meet the continuing professional development (CPD) standards of the Nursing and Midwifery Board of Australia.</p><p><strong>(b)</strong> CPD means activities that maintain knowledge in the Employee&#39;s current area of practice, improve and broaden their knowledge, expertise and competence, and develop the personal and professional qualities required through their professional lives. The CPD cycle involves:</p><p><strong>(i)</strong> reviewing practice;</p><p><strong>(ii)</strong> identifying learning needs;</p><p><strong>(iii)</strong> planning and participating in relevant learning activities; and</p><p><strong>(iv)</strong> reflecting on the value of those activities.</p><p><strong>(c)</strong> Professional development leave includes conference/seminar leave and may also be utilised for activities including research or home study.</p><p><strong>75.2</strong> Amount of professional development leave</p><p><strong>(a)</strong> All Employees are entitled to five days&#39; paid professional development leave (as defined in subclause 75.1(b)).</p><p><strong>(b)</strong> An Employee who is a Nurse Practitioner will be entitled to a further 10 hours of paid professional development leave per annum.</p><p><strong>(c)</strong> The entitlement at (a) above for part-time Employees will be on a pro rata basis.</p><p><strong>(d)</strong> Professional development leave does not accumulate from year to year.</p><p><strong>75.3</strong> Payment</p><p>A day for the purposes of professional development leave is the Employee&#39;s normal shift length. For example, a night shift worker who takes professional development leave for a 10-hour night shift is entitled to 10 hours&#39; payment.</p><p><strong>75.4</strong> Application</p><p>Professional development leave is available only on written application by the Employee. An Employee must apply in writing to the Employer at least six weeks prior to the proposed professional development leave date. If the professional development leave is to undertake home study, the Employee&#39;s application will detail the relevance of the study to the Employee&#39;s employment.</p><p><strong>75.5</strong> Response to application</p><p><strong>(a)</strong> An application for professional development leave will be approved by the Employer unless there are exceptional circumstances that justify non-approval.</p><p><strong>(b)</strong> The Employer must notify the Employee in writing whether the leave request is approved within seven days.</p><p><strong>(c)</strong> If the leave is not approved, the reasons will be included in the notification to the Employee.</p><p><strong>(d)</strong> The use of professional development leave is at the sole discretion of the Employee and except for the conditions in this clause, no other conditions attach to the granting of professional development leave.</p><p><strong>75.6</strong> Leave not granted</p><p>Where a valid application is made for professional development leave (in whole or part) but no leave is granted during the calendar year, one day&#39;s leave will be added to the Employee&#39;s accrued annual leave, or taken in another manner as mutually agreed between the Employer and the Employee.</p><p><strong>75.7</strong> Where leave occurs on a rostered day off</p><p>Professional development leave need not take place on a day that the Employee would otherwise work. In those circumstances the Employer will do one of the following:</p><p><strong>(a)</strong> allocation of a day&#39;s professional development leave paid at the ordinary rate of pay;</p><p><strong>(b)</strong> time off in lieu on a mutually agreed day, to be granted within 28 days;</p><p><strong>(c)</strong> where time off in lieu is not agreed or does not occur within 28 days, an additional day&#39;s ordinary pay; or</p><p><strong>(d)</strong> an additional day&#39;s annual leave which will not attract leave loading.</p><p><strong>75.8</strong> Mandatory Training</p><p><strong>(a)</strong> Any education or training deemed compulsory or mandatory by the Employer will occur within an Employee&#39;s paid time, and overtime applies where it would otherwise apply. No deduction will be made to an Employee&#39;s annual professional development leave for mandatory training.</p>',34)])])}const c=o(s,[["render",r]]);export{h as __pageData,c as default};
